package samples.spring.org.apache.shiro.samples.spring;

@ Component public class QuickStart { private static Logger log = LoggerFactory . getLogger ( QuickStart . class ) ; @ Autowired private SecurityManager securityManager ; @ Autowired private SimpleService simpleService ; public void run ( ) { Subject subject = SecurityUtils . getSubject ( ) ; Assert . isTrue ( ! subject . isAuthenticated ( ) ) ; UsernamePasswordToken token = new UsernamePasswordToken ( "joe.coder" , "password" ) ; subject . login ( token ) ; subject . checkRole ( "user" ) ; Assert . isTrue ( ! subject . hasRole ( "admin" ) ) ; subject . checkPermission ( "read" ) ; simpleService . readRestrictedCall ( ) ; try { simpleService . writeRestrictedCall ( ) ; } catch ( AuthorizationException e ) { log . info ( "Subject was NOT allowed to execute method 'writeRestrictedCall'" ) ; } subject . logout ( ) ; Assert . isTrue ( ! subject . isAuthenticated ( ) ) ; } @ PostConstruct private void initStaticSecurityManager ( ) { SecurityUtils . setSecurityManager ( securityManager ) ; } }